frappe.ui.form.on("Item", {
	setup(frm) {
		if (frm.fields_dict.default_location) {
			frm.set_query("default_location", () => {
				const filters = { enabled: 1 };
				if (frm.doc.supply_warehouse) {
					filters.warehouse = frm.doc.supply_warehouse;
				}
				return { filters };
			});
		}
	},

	refresh(frm) {
		syncItemUsageDefaults(frm, false);
	},

	item_usage_type(frm) {
		syncItemUsageDefaults(frm, true);
	},

	supply_warehouse(frm) {
		if (!frm.doc.default_location) {
			return;
		}

		frappe.db.get_value("Warehouse Location", frm.doc.default_location, "warehouse").then((response) => {
			const row = response.message || {};
			if (row.warehouse && frm.doc.supply_warehouse && row.warehouse !== frm.doc.supply_warehouse) {
				frm.set_value("default_location", "");
			}
		});
	}
});

function syncItemUsageDefaults(frm, updateFields) {
	const usage = frm.doc.item_usage_type;
	if (!usage) {
		return;
	}

	if (updateFields) {
		if (usage === "成品") {
			frm.set_value("sellable", 1);
			frm.set_value("supply_mode", "不适用");
			frm.set_value("is_fulfillment_consumable", 0);
		} else {
			frm.set_value("sellable", 0);
			if (!frm.doc.supply_mode || frm.doc.supply_mode === "不适用") {
				frm.set_value("supply_mode", "自供");
			}
			frm.set_value("is_fulfillment_consumable", usage === "包装耗材" ? 1 : 0);
		}
		if (["面料", "辅料", "包装耗材"].includes(usage) && frm.doc.is_stock_item !== 1) {
			frm.set_value("is_stock_item", 1);
		}
	}
}

frappe.ui.form.on("Sales Order", {
	channel_store(frm) {
		if (!frm.doc.channel_store) {
			return;
		}

		frappe.db.get_value("Channel Store", frm.doc.channel_store, "channel").then((response) => {
			const row = response.message || {};
			if (row.channel) {
				frm.set_value("channel", row.channel);
			}
		});
	}
});

frappe.ui.form.on("Sales Order Item", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "color_name", "size_code", "size_name"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "color_name", item.color_name || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
			frappe.model.set_value(cdt, cdn, "size_name", item.size_name || "");
		});
	}
});

frappe.ui.form.on("Stock Entry Detail", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "size_code"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
		});
	},

	production_ticket(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			row.production_ticket,
			["style", "color_code", "item_template"]
		).then((response) => {
			const ticket = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", ticket.style || row.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", ticket.color_code || row.color_code || "");
			if (!row.item_code && ticket.item_template) {
				frappe.model.set_value(cdt, cdn, "item_code", ticket.item_template);
			}
		});
	},

	return_disposition(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.return_disposition) {
			return;
		}

		frappe.db.get_value(
			"Return Disposition",
			row.return_disposition,
			"target_inventory_status"
		).then((response) => {
			const disposition = response.message || {};
			if (disposition.target_inventory_status) {
				frappe.model.set_value(cdt, cdn, "inventory_status_to", disposition.target_inventory_status);
			}
		});
	}
});

frappe.ui.form.on("Stock Entry", {
	setup(frm) {
		const grid = frm.fields_dict.items && frm.fields_dict.items.grid;
		if (!grid) {
			return;
		}

		["inventory_status_from", "inventory_status_to"].forEach((fieldname) => {
			grid.get_field(fieldname).get_query = function () {
				return {
					filters: {
						enabled: 1
					}
				};
			};
		});

		["return_reason", "return_disposition"].forEach((fieldname) => {
			grid.get_field(fieldname).get_query = function () {
				return {
					filters: {
						enabled: 1
					}
				};
			};
		});
	}
});

frappe.ui.form.on("Work Order", {
	production_ticket(frm) {
		if (!frm.doc.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			frm.doc.production_ticket,
			["style", "color_code", "item_template", "bom_no", "qty"]
		).then((response) => {
			const ticket = response.message || {};
			if (ticket.style) {
				frm.set_value("style", ticket.style);
			}
			if (ticket.color_code) {
				frm.set_value("color_code", ticket.color_code);
			}
			if (!frm.doc.production_item && ticket.item_template) {
				frm.set_value("production_item", ticket.item_template);
			}
			if (!frm.doc.bom_no && ticket.bom_no) {
				frm.set_value("bom_no", ticket.bom_no);
			}
			if (!frm.doc.qty && ticket.qty) {
				frm.set_value("qty", ticket.qty);
			}
		});
	}
});

frappe.ui.form.on("BOM", {
	production_ticket(frm) {
		if (!frm.doc.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			frm.doc.production_ticket,
			["style", "color_code", "item_template"]
		).then((response) => {
			const ticket = response.message || {};
			if (ticket.style) {
				frm.set_value("style", ticket.style);
			}
			if (ticket.color_code) {
				frm.set_value("color_code", ticket.color_code);
			}
			if (!frm.doc.item && ticket.item_template) {
				frm.set_value("item", ticket.item_template);
			}
		});
	}
});
